void rbs_serializer_write_u8(rbs_serializer_t *serializer, uint8_t value) {
    rbs_buffer_append_string(serializer->allocator, serializer->buffer, (const char *) &value, 1);
}

void rbs_serializer_write_u32(rbs_serializer_t *serializer, uint32_t value) {
    char bytes[4] = {
        (char) (value & 0xff),
        (char) ((value >> 8) & 0xff),
        (char) ((value >> 16) & 0xff),
        (char) ((value >> 24) & 0xff),
    };
    rbs_buffer_append_string(serializer->allocator, serializer->buffer, bytes, 4);
}

void rbs_serializer_write_i32(rbs_serializer_t *serializer, int32_t value) {
    rbs_serializer_write_u32(serializer, (uint32_t) value);
}

void rbs_serializer_write_string(rbs_serializer_t *serializer, rbs_string_t string) {
    size_t length = rbs_string_len(string);
    rbs_serializer_write_u32(serializer, (uint32_t) length);
    rbs_buffer_append_string(serializer->allocator, serializer->buffer, string.start, length);
}

